export function initialize(dotNetRef, element, timeoutMs) {
    let timer = null;
    let isIdle = false;

    function resetTimer() {
        if (timer) clearTimeout(timer);
        if (isIdle) {
            isIdle = false;
            dotNetRef.invokeMethodAsync("OnUserActive");
        }
        timer = setTimeout(() => {
            isIdle = true;
            dotNetRef.invokeMethodAsync("OnUserIdle");
        }, timeoutMs);
    }

    const events = ["mousemove", "keydown", "click", "scroll", "touchstart"];
    events.forEach(e => element.addEventListener(e, resetTimer, { passive: true }));

    // Start the initial timer
    timer = setTimeout(() => {
        isIdle = true;
        dotNetRef.invokeMethodAsync("OnUserIdle");
    }, timeoutMs);

    return {
        dispose() {
            if (timer) clearTimeout(timer);
            events.forEach(e => element.removeEventListener(e, resetTimer));
        }
    };
}

